import base64
import json

b64_str = "_c3NsbW9kZT1kaXNhYmxlJmNvbm5lY3Rpb25fbGltaXQ9MTAmY29ubmVjdF90aW1lb3V0PTAmbWF4X2lkbGVfY29ubmVjdGlvbl9saWZldGltZT0wJnBvb2xfdGltZW91dD0wJnNvY2tldF90aW1lb3V0PTAifQ"

print("Length:", len(b64_str))

# Add padding
b64_str = b64_str.replace("_", "/").replace("-", "+")
missing_padding = len(b64_str) % 4
if missing_padding:
    b64_str += '=' * (4 - missing_padding)

print("Padded Length:", len(b64_str))
decoded = base64.b64decode(b64_str)
print("Decoded:")
print(json.dumps(json.loads(decoded.decode('utf-8')), indent=2))
